package com.restaurantcraft.entity.ai; import com.restaurantcraft.blockentity.RestaurantChairBlockEntity; import com.restaurantcraft.entity.*; import com.restaurantcraft.util.RestaurantCustomerUtil; import net.minecraft.core.BlockPos; import net.minecraft.world.entity.ai.goal.Goal; public class FindRestaurantSeatGoal extends Goal { private final CustomerEntity c; public FindRestaurantSeatGoal(CustomerEntity c){this.c=c;} public boolean canUse(){return c.state()==CustomerState.FINDING_SEAT;} public void tick(){ if(c.chairPos()==null){BlockPos p=RestaurantCustomerUtil.findFreeChair(c.level(),c.restaurantPos()); if(p!=null){c.setChair(p); if(c.level().getBlockEntity(p) instanceof RestaurantChairBlockEntity be)be.setOccupied(true);}} if(c.chairPos()!=null){c.getNavigation().moveTo(c.chairPos().getX()+0.5,c.chairPos().getY(),c.chairPos().getZ()+0.5,1.0); if(c.blockPosition().closerThan(c.chairPos(),1.5))c.sitAndOrder();}} }
